// Comprehensive Syllable Master Lab - UPDATED FOR COMPACT MODE (NO IMAGES)
export const generateSyllableMasterLabFromAI = async (options: GeneratorOptions): Promise<SyllableMasterLabData[]> => {
    const { worksheetCount, difficulty, itemCount, topic, variant = 'split', case: letterCase } = options;

    const specifics = `
    - ÇALİŞMA MODU: ${variant} (split, combine, complete, rainbow, scrambled)
    - KONU: ${topic || 'Karma'}
    - HARF TİPİ: ${letterCase === 'upper' ? 'BÜYÜK' : 'küçük'}
    - ADET: ${itemCount || 12} kelime (A4 sayfasını dolduracak şekilde yoğun üret).
    - ZORLUK: ${difficulty}.

    ÖNEMLİ KURALLAR:
    1. GÖRSEL KULLANMA: Bu etkinlik sadece metin tabanlıdır, kesinlikle görsel/imagePrompt üretme.
    2. 'split': Kelimeyi ver, hece kutucuklarını boş bırak.
    3. 'combine': Heceleri yan yana ver, birleşimi iste.
    4. 'complete': Bir heceyi eksik bırak.
    5. 'rainbow': Kelimenin her hecesini farklı vurguda planla.
    6. 'scrambled': Heceleri rastgele sırala.
    `;

    const prompt = getDyslexiaPrompt("Hece Ustası Laboratuvarı (Kompakt Mod)", difficulty, specifics, options.studentContext);

    const singleSchema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            mode: { type: Type.STRING },
            items: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        word: { type: Type.STRING },
                        syllables: { type: Type.ARRAY, items: { type: Type.STRING } },
                        missingIndex: { type: Type.INTEGER, nullable: true },
                        scrambledIndices: { type: Type.ARRAY, items: { type: Type.INTEGER }, nullable: true }
                        // imagePrompt removed
                    },
                    required: ['word', 'syllables']
                }
            }
        },
        required: ['title', 'instruction', 'items', 'pedagogicalNote']
    };

    return await generateWithSchema(prompt, { type: Type.ARRAY, items: singleSchema }) as any;
};

