                    )}

                    {/* MODE: COMBINE */}
                    {isCombine && (
                        <div className="flex flex-col items-center gap-2">
                            <div className="flex gap-1 flex-wrap justify-center">
                                {item.syllables.map((s:string, sIdx:number) => (
                                    <div key={sIdx} className="px-2 py-1 bg-zinc-900 text-white rounded-lg font-black text-xs">
                                        <EditableText value={s} tag="span" />
                                    </div>
                                ))}
                            </div>
                            <div className="w-full h-8 border-b-[2px] border-dashed border-zinc-300 bg-zinc-50 rounded-t-lg"></div>
                        </div>
                    )}

                    {/* MODE: COMPLETE */}
                    {isComplete && (
                        <div className="flex items-center justify-center gap-1">
                             {item.syllables.map((s:string, sIdx:number) => {
                                 const isMissing = sIdx === item.missingIndex;
                                 return (
                                     <div key={sIdx} className={`px-2 py-1.5 rounded-lg font-black text-sm border-[2px] ${isMissing ? 'border-dashed border-indigo-400 bg-indigo-50 text-transparent' : 'border-zinc-900 bg-white text-zinc-800'}`}>
                                         {isMissing ? '..' : <EditableText value={s} tag="span" />}
                                     </div>
                                 );
                             })}
                        </div>
                    )}

                    {/* MODE: RAINBOW */}
                    {isRainbow && (
                        <div className="flex items-center justify-center gap-1 flex-wrap">
                            {item.syllables.map((s:string, sIdx:number) => {
                                const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6'];
                                return (
                                    <div key={sIdx} className="px-2 py-1 rounded-lg border-[2px] border-zinc-900 shadow-sm" style={{ backgroundColor: `${colors[sIdx % colors.length]}10`, color: colors[sIdx % colors.length] }}>
                                        <span className="text-lg font-black tracking-tight"><EditableText value={s} tag="span" /></span>
                                    </div>
                                );
                            })}
                        </div>
                    )}

                    {/* MODE: SCRAMBLED */}
                    {isScrambled && (
                        <div className="flex flex-col gap-3">
                            <div className="flex gap-1 flex-wrap justify-center">
                                {item.scrambledIndices?.map((origIdx: number) => (
                                    <div key={origIdx} className="px-2 py-1 bg-white border border-zinc-300 rounded-full font-bold text-[10px] text-zinc-600 shadow-xs">
                                        <EditableText value={item.syllables[origIdx]} tag="span" />
                                    </div>
                                ))}
                            </div>
                            <div className="flex gap-0.5 px-2">
                                {item.syllables.map((_:string, i:number) => (
                                    <div key={i} className="flex-1 h-6 border-b-[2px] border-zinc-900 bg-zinc-50/50"></div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </EditableElement>
        );
    };

    return (
        <div className="flex flex-col h-full bg-white font-lexend p-2">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} data={data} />
            <div className="flex-1 grid grid-cols-2 md:grid-cols-3 gap-3 mt-4 content-start">
                {items.map((item, i) => renderItem(item, i))}
            </div>
            <div className="mt-auto pt-4 border-t border-zinc-100 flex justify-between items-center px-4 opacity-40">
                <p className="text-[7px] text-zinc-400 font-bold uppercase tracking-[0.4em]">Bursa Disleksi AI • Hece Laboratuvarı v3.0 (Kompakt)</p>
            </div>
        </div>
    );
};

