                                { value: 'fruits_veggies', label: 'Meyve & Sebze' },
                                { value: 'school', label: 'Okul Eşyaları' },
                                { value: 'items_household', label: 'Ev Eşyaları' },
                                { value: 'abstract', label: 'Soyut Kavramlar' },
                                { value: 'mixed', label: 'Karma Havuz' }
