export const generateMathMemoryCardsFromAI = async (options: GeneratorOptions): Promise<MathMemoryCardsData[]> => {
    const { worksheetCount, difficulty, itemCount = 16, variant = 'op-res', selectedOperations = ['add'] } = options;

    const prompt = `
    [GÖREV: MATEMATİK HAFIZA KARTLARI ÜRET]
    ZORLUK: ${difficulty}
    TOPLAM KART SAYISI: ${itemCount} (${itemCount / 2} çift)
    VARYANT: ${variant} (op-res: İşlem-Sonuç, vis-num: Görsel-Sayı, eq-eq: Denk İşlemler)
    İŞLEMLER: ${selectedOperations.join(', ')}

    TASARIM KURALLARI:
    1. Her bir çift kart için 'pairId' alanı aynı olmalıdır.
    2. 'type' alanı 'operation', 'number', 'visual' veya 'text' olabilir.
    3. 'vis-num' varyantında bir kart mutlaka 'visual' tipinde olmalı ve 'visualType' belirtilmelidir.
    4. Sayılar ve işlemler zorluk seviyesine (${difficulty}) tam uygun olmalıdır.
    5. 'content' alanına kartın üzerinde görünecek metni veya görsel promptu yaz.

    ÇIKTI: Her sayfa için A4'ü dolduracak yoğunlukta kart dizisi döndür.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                cards: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            pairId: { type: Type.STRING },
                            type: { type: Type.STRING, enum: ['operation', 'number', 'visual', 'text'] },
                            content: { type: Type.STRING },
                            visualType: { type: Type.STRING, nullable: true },
                            numValue: { type: Type.NUMBER }
                        },
                        required: ['id', 'pairId', 'type', 'content', 'numValue']
                    }
                }
            },
            required: ['title', 'instruction', 'cards']
        }
    };

    return await generateWithSchema(prompt, schema) as any;
};

