// Compact UI Components for the generator
const CompactSelect = ({ label, value, onChange, options, icon }: any) => (
    <div className="flex flex-col gap-1">
        <label className="text-[10px] font-bold text-zinc-500 uppercase flex items-center gap-2">
            <i className={`fa-solid ${icon}`}></i> {label}
        </label>
        <select 
            value={value} 
            onChange={(e) => onChange(e.target.value)}
            className="p-2.5 rounded-xl border border-zinc-200 dark:border-zinc-700 bg-white dark:bg-zinc-900 text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500"
        >
            {options.map((o: any) => <option key={o.value} value={o.value}>{o.label}</option>)}
        </select>
    </div>
);

const CompactCounter = ({ label, value, onChange, min, max, icon }: any) => (
    <div className="flex items-center justify-between">
        <label className="text-[10px] font-bold text-zinc-500 uppercase flex items-center gap-2">
            <i className={`fa-solid ${icon}`}></i> {label}
        </label>
        <div className="flex items-center gap-3">
            <button onClick={() => onChange(Math.max(min, value - 1))} className="w-8 h-8 rounded-lg bg-zinc-100 dark:bg-zinc-700 text-zinc-600 dark:text-zinc-300">-</button>
