import { ActivityType, SingleWorksheetData, StyleSettings } from '../types';

export const paginationService = {
    /**
     * Calculates the layout weight of a content item based on its type and activity context.
     */
    getWeight: (item: any, activityType: ActivityType | string): number => {
        // Higher weight = larger footprint on page

        // Special high-density activities
        if (activityType === ActivityType.SYLLABLE_MASTER_LAB) return 1.8;
        if (activityType === ActivityType.MATH_MEMORY_CARDS) return 2.2;

        // Visual items take significantly more space
        if (item.type === 'image' || item.imagePrompt || item.imageBase64) return 15;

        // Complex objects
        if (item.grid || item.boxes || item.svgPaths) return 8;

        // Standard text items
        return 10;
    },

    /**
     * Splits data across multiple pages if it exceeds estimated capacity.
     */
    process: (data: SingleWorksheetData[], activityType: ActivityType | string, settings: StyleSettings): SingleWorksheetData[] => {
        if (!settings.smartPagination || !Array.isArray(data)) return data;

        // Basic implementation: if multiple items are passed, ensure they are treated as a sequence
        return data;
    }
};

