                    },
                    required: ['word', 'syllables', 'syllableCount']
                }
            }
        },
        required: ['title', 'instruction', 'items', 'pedagogicalNote']
    };

    return await generateWithSchema(prompt, { type: Type.ARRAY, items: singleSchema }) as any;
};

