                                        {Array.from({length: Math.min(20, prob.num1)}).map((_,i) => <div key={i} className="w-4 h-4 bg-indigo-500 rounded-full"></div>)}
                                    </div>
                                )}
                                {visual === 'number-bond' && <NumberBond whole={prob.operator === '+' ? prob.answer : prob.num1} part1={prob.operator === '+' ? prob.num1 : prob.num2} part2={prob.operator === '+' ? prob.num2 : prob.answer} isAddition={prob.operator === '+'} />}
                                {visual !== 'number-bond' && prob.operator !== 'group' && <span className="text-3xl font-bold text-zinc-400"><EditableText value={prob.operator} tag="span" /></span>}
                                {visual !== 'number-bond' && prob.operator !== 'group' && (
                                    <>
                                        {visual === 'ten-frame' && <TenFrame count={prob.num2} />}
                                        {visual === 'dice' && <Domino count={prob.num2} />}
                                        {visual === 'blocks' && <Base10Visualizer number={prob.num2} className="scale-75 origin-center" />}
                                        {(visual === 'objects' || visual === 'mixed') && (
                                            <div className="flex flex-wrap gap-1 w-24 justify-center">
                                                {Array.from({length: Math.min(20, prob.num2)}).map((_,i) => <div key={i} className="w-4 h-4 bg-rose-500 rounded-full"></div>)}
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                            {visual !== 'number-bond' && (
                                <div className="flex items-center gap-2 text-2xl font-bold font-mono">
                                    {prob.operator === 'group' ? (
                                        <><EditableText value={prob.num1} tag="span" /> grup x <EditableText value={prob.num2} tag="span" /> = <div className="w-16 h-10 border-2 border-zinc-400 rounded bg-white text-center"><EditableText value="" tag="span" /></div></>
                                    ) : (
                                        <><EditableText value={prob.num1} tag="span" /> <EditableText value={prob.operator} tag="span" /> <EditableText value={prob.num2} tag="span" /> = <div className="w-16 h-10 border-2 border-zinc-400 rounded bg-white text-center"><EditableText value="" tag="span" /></div></>
                                    )}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

