 */
export type MathMode = 'drill' | 'problem_ai';

/**
 * Configuration for the layout of a math worksheet page.
 */
export interface MathPageConfig {
    paperType: 'blank' | 'grid' | 'dot';
    gridSize: number;
    margin: number;
    showDate: boolean;
    showName: boolean;
    title: string;
}

