    cols: number;
    gap: number;
    allowCarry: boolean;
    allowBorrow: boolean;
    allowRemainder: boolean;
    allowNegative: boolean;
    useThirdNumber: boolean;
    showTextRepresentation: boolean;
    autoFillPage: boolean;
    orientation: 'vertical' | 'horizontal';
