const MoneyItem: React.FC<{ value: number, type: 'coin' | 'note', count?: number }> = ({ value, type, count = 1 }) => {
    // Kağıt Para Renkleri (TL Standartları)
    const noteColors: Record<number, string> = {
        5: 'bg-violet-100 border-violet-400 text-violet-700',
        10: 'bg-rose-100 border-rose-400 text-rose-700',
        20: 'bg-emerald-100 border-emerald-400 text-emerald-700',
        50: 'bg-amber-100 border-amber-400 text-amber-700',
        100: 'bg-blue-100 border-blue-400 text-blue-700',
        200: 'bg-fuchsia-100 border-fuchsia-400 text-fuchsia-700'
    };

    return (
        <div className="flex flex-wrap gap-1">
            {Array.from({ length: count }).map((_, i) => (
                type === 'coin' ? (
                    <div key={i} className={`w-12 h-12 rounded-full border-2 flex items-center justify-center font-black shadow-sm ${value >= 1 ? 'bg-amber-400 border-amber-600 text-amber-900 ring-2 ring-amber-200' : 'bg-zinc-200 border-zinc-400 text-zinc-600'}`}>
                        <div className="flex flex-col items-center leading-none">
                            <span className="text-sm">{value < 1 ? value * 100 : value}</span>
                            <span className="text-[7px] uppercase font-bold">{value < 1 ? 'Kr' : 'TL'}</span>
                        </div>
                    </div>
                ) : (
                    <div key={i} className={`w-24 h-12 border-2 rounded-lg flex items-center justify-center font-black relative overflow-hidden shadow-md ${noteColors[value] || 'bg-zinc-100'}`}>
                        <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[radial-gradient(circle,_currentColor_1px,_transparent_1px)] bg-[length:8px_8px]"></div>
                        <div className="flex flex-col items-center z-10 leading-none">
                            <span className="text-base">{value}</span>
                            <span className="text-[8px] uppercase tracking-tighter">Türk Lirası</span>
                        </div>
                        <div className="absolute bottom-1 right-1 opacity-20 text-[10px]"><i className="fa-solid fa-building-columns"></i></div>
                    </div>
                )
            ))}
        </div>
    );
};

