                                        <><EditableText value={prob.num1} tag="span" /> <EditableText value={prob.operator} tag="span" /> <EditableText value={prob.num2} tag="span" /> = <div className="w-16 h-10 border-2 border-zinc-400 rounded bg-white text-center"><EditableText value="" tag="span" /></div></>
                                    )}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
};

