export const QUESTION_TYPES: Record<string, { label: string; color: string; bg: string; border: string }> = {
    who: { label: 'KİM?', color: '#ef4444', bg: '#fef2f2', border: '#fecaca' },
    what: { label: 'NE?', color: '#3b82f6', bg: '#eff6ff', border: '#bfdbfe' },
