import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions } from '../../types';
import { MathPuzzleData, ShapeCountingData } from '../../types';
import { getMathPrompt } from './prompts';

export const generateMathPuzzleFromAI = async (options: GeneratorOptions): Promise<MathPuzzleData[]> => {
    const { topic, itemCount = 4, difficulty, worksheetCount, operationType, numberRange, studentContext } = options;

    const opsMap: Record<string, string> = {
        'add': 'Sadece Toplama (+)',
        'sub': 'Toplama ve Çıkarma (+, -)',
        'mult': 'Çarpma odaklı (x)',
        'mixed': 'Dört İşlem Karışık (+, -, x, ÷)'
    };

    const rule = `
    [GÖREV: GÖRSEL MATEMATİK BULMACALARI ÜRET]
    ZORLUK SEVİYESİ: ${difficulty}
    TEMA: ${topic || 'Karma'}
    İŞLEMLER: ${opsMap[operationType || 'add']}
    SAYI ARALIĞI: ${numberRange || '1-20'}

    TASARIM KURALLARI:
    1. Her sayfada ${itemCount} adet bağımsız bulmaca kutusu (Bento Box) planla.
    2. Her bulmaca için 3 adet benzersiz obje tanımla (ID'leri: obj1, obj2, obj3).
    3. Denklemler (equations) dizisinde bu objeleri sembolik olarak kullan. 
       Örn: ["obj1 + obj1 = 10", "obj1 + obj2 = 12", "obj2 + obj3 = 7"]
    4. Soru (question) her zaman en az bir değişkenin toplamını/farkını sorsun. 
       Örn: "obj1 + obj2 + obj3 = ?"
    5. Zorluk Ayarı:
       - Başlangıç: 2 obje, sadece toplama, 1-10 arası sayılar.
       - Orta: 3 obje, toplama/çıkarma, 1-20 arası sayılar.
       - Zor: 3-4 obje, çarpma dahil, işlem önceliği (parenthesis) içerebilir.
       - Uzman: Karmaşık denklemler, rasyonel sonuçlar veya 3 aşamalı mantık zinciri.

    ÇIKTI: JSON dizi formatında döndür.
    `;

    const prompt = getMathPrompt("Görsel Matematik Bulmacaları", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                objects: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            name: { type: Type.STRING },
                            imagePrompt: { type: Type.STRING }
                        },
                        required: ['id', 'name', 'imagePrompt']
                    }
                },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            equations: { type: Type.ARRAY, items: { type: Type.STRING } },
                            question: { type: Type.STRING },
                            answer: { type: Type.STRING }
                        },
                        required: ['id', 'equations', 'question', 'answer']
                    }
                }
            },
            required: ['title', 'instruction', 'objects', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

export const generateShapeCountingFromAI = async (options: GeneratorOptions): Promise<ShapeCountingData[]> => {
    // ... (rest of the file remains same)
    const { difficulty, worksheetCount } = options;
    const prompt = `
    "${difficulty}" seviyesinde "Şekil Sayma" (Örn: Kaç üçgen var?).
    Karmaşık, iç içe geçmiş şekillerden oluşan SVG path verileri üret.
    SVG pathleri 'd' attribute olarak ve renkleri 'fill' olarak ver.
    Şekiller birbirini kesmeli ve dikkatli saymayı gerektirmeli.
    ${worksheetCount} adet üret.
    `;
    const singleSchema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            imagePrompt: { type: Type.STRING },
            figures: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        svgPaths: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    d: { type: Type.STRING },
                                    fill: { type: Type.STRING }
                                },
                                required: ["d", "fill"]
                            }
                        },
                        targetShape: { type: Type.STRING },
                        correctCount: { type: Type.INTEGER }
                    },
                    required: ["svgPaths", "targetShape", "correctCount"]
                }
            }
        },
        required: ["title", "instruction", "figures", "pedagogicalNote", "imagePrompt"]
    };
    const schema = { type: Type.ARRAY, items: singleSchema };
    return generateWithSchema(prompt, schema) as Promise<ShapeCountingData[]>;
};

